# To run this code you need to install the following dependencies:
# pip install google-genai

import base64
import os
from google import genai
from google.genai import types


def generate():
    client = genai.Client(
        api_key=os.environ.get("GEMINI_API_KEY"),
    )

    model = "gemini-3-pro-preview"
    contents = [
        types.Content(
            role="user",
            parts=[
                types.Part.from_bytes(
                    mime_type="image/png",
                    data=base64.b64decode(
                        """"""
                    ),
                ),
                types.Part.from_bytes(
                    mime_type="image/png",
                    data=base64.b64decode(
                        """"""
                    ),
                ),
                types.Part.from_bytes(
                    mime_type="image/png",
                    data=base64.b64decode(
                        """"""
                    ),
                ),
                types.Part.from_text(text="""\"Analyze the progression of facial expressions, body movement, and context across these frames step-by-step. How do the visual cues change from the first to the last frame? Based on this temporal analysis, choose ONE emotion from: **joy, anger, fear, sadness, surprise, neutral**. Format your final answer as: **<final>Conclusion: the dominant emotion is EMOTION.</final>**\"
"""),
            ],
        ),
        types.Content(
            role="model",
            parts=[
                types.Part.from_text(text="""**Analyzing Initial Reactions**

I've begun examining the first image, focusing on the woman's reaction. Her hand-to-mouth gesture and wide eyes suggest surprise or even shock. The man's upward gaze and smile seem to indicate hopeful anticipation. I am considering these initial reactions as I analyze the whole scene.


**Interpreting Subsequent Scenes**

I've moved on to the subsequent images. Image two depicts a clear \"yes\" moment, with an embrace that speaks volumes. The third image shows a broad smile and motion, probably suggesting the man is now rising to embrace her more closely, or to put the ring on. These elements are coalescing into a clear narrative.


**Re-evaluating Narrative Flow**

I'm reconsidering the sequence. Image 3 seems out of order, possibly representing anticipation *before* the hug in image 2. The man's blurriness in Image 3 indicates movement, and the woman's calm smile suggests happy anticipation. I'm now testing the hypothesis that the sequence is anticipation, proposal, then joy. This is critical for interpreting the full emotional progression.


**Sequencing the Narrative**

I'm now revising my interpretation of the scene's progression. It seems the \"Right\" image, initially considered as the end, might actually be the beginning, indicating the man moving into the scene, perhaps to propose or rising to embrace. I'm exploring the hypothesis that the sequence is 3 -> 1 -> 2, or perhaps 1 -> 2 -> 3. The current theory is that the third frame sets the stage before the proposal.


**Refining Interpretations**

I've refined my interpretations of the frames, assigning emotions and actions to each. The analysis clearly points to a progression from positive surprise to joy, with the man proposing and the woman's reaction transforming into happiness. I'm now certain about choosing \"joy\" as the dominant emotion, encompassing the whole scene. I'm now confident in the order 1 -> 2 -> 3.


**Determining Dominant Emotion**

I'm now prioritizing joy as the primary emotion across the frames, as the analysis shows surprise being a transient state. While there's surprise in Frame 1, it quickly shifts to happiness, a dominant joy in the embrace of Frame 2. Frame 3 continues with joy and happiness, especially in light of the context of a proposal. Fear, anger, sadness, and neutrality are definitely not present. This dominant emotional state is key.


**Confirming Overall Emotion**

The \"middle\" frame really cements the overall feeling. The third frame's smiles further confirms that my original assessment of joy is most accurate. My current plan is to use that as an all-encompassing descriptor. I am now refining each frame's analysis further, building a cohesive narrative around the couple's overwhelmingly positive experience.


"""),
                types.Part.from_text(text="""Based on the temporal analysis of the three frames:

1.  **Frame 1 (Left):** The scene depicts the peak moment of a marriage proposal. The man is on one knee holding a ring box. The woman’s body language—hands covering her mouth—signals a high-intensity reaction, primarily **surprise** mixed with delight. The context establishes this as a positive, life-changing event.

2.  **Frame 2 (Middle):** The progression moves to physical intimacy. The couple is locked in a tight embrace, with the man leaning in while still kneeling and the woman wrapping her arms around him. This cues the resolution of the surprise into acceptance and deep affection. The body language here signifies relief and overwhelming happiness.

3.  **Frame 3 (Right):** The man appears to be in motion (blurred), likely standing up or transitioning, while the woman stands with a relaxed, broad smile on her face. Her expression has shifted from shock (Frame 1) to a steady, beaming demeanor. This indicates a lingering state of contentment and happiness after the initial shock has subsided.

**Conclusion:**
While the first frame features surprise, the narrative arc across all three frames—moving from the shock of the proposal to the warm embrace and finally to the beaming smiles—is defined by the celebration of love and happiness. The surprise is merely the catalyst for the enduring emotional state.

<final>Conclusion: the dominant emotion is JOY.</final>"""),
            ],
        ),
        types.Content(
            role="user",
            parts=[
                types.Part.from_text(text="""INSERT_INPUT_HERE"""),
            ],
        ),
    ]
    tools = [
        types.Tool(googleSearch=types.GoogleSearch(
        )),
    ]
    generate_content_config = types.GenerateContentConfig(
        thinking_config=types.ThinkingConfig(
            thinking_level="HIGH",
        ),
        tools=tools,
    )

    for chunk in client.models.generate_content_stream(
        model=model,
        contents=contents,
        config=generate_content_config,
    ):
        print(chunk.text, end="")

if __name__ == "__main__":
    generate()
